INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "訓練成功、おめでとうございます\n褒めるべき時にはしっかり褒めるのも\n教官の務めですものね。それとも、\n罵られる方が好みですか？　クスクス", 1, 7, 0.0, 10142, 100, 24, 129901, 100, "2030/12/17 14:59:59", 0.0, 10.85, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "厳しい訓練も、終わってみれば\n短く感じるものですわね。\n正直、私は暴れ足りないくらい…\nいえ、何でもありませんわ。クスクス", 1, 2, 0.0, 10142, 101, 24, 129901, 101, "2030/12/17 14:59:59", 0.0, 11.15, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "行く手を阻む忌々しい邪魔者を\n蹴散らして、見事ゴールイン…！\nまるで私とあのおかたの人生を\n象徴するような道のりでした…", 7, 5, 0.0, 10142, 102, 24, 129901, 102, "2030/12/17 14:59:59", 0.0, 6.4, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "まったくもって不甲斐ない結果です\nしかし、挽回の機会はまだありますわ\n次はゴミ虫の地位から脱却できるよう\n死力を尽くしなさい。いいですね？", 3, 3, 0.0, 10142, 103, 24, 129901, 103, "2030/12/17 14:59:59", 0.0, 0.0, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "クスクス…ああご心配なさらず\nなんとも情けない成績を残す輩には\nどんな罰が相応しいか、考えている\nだけですので…クスクスクス", 2, 8, 0.0, 10142, 104, 24, 129901, 104, "2030/12/17 14:59:59", 0.0, 2.43, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "私が教官として認められなければ、\nあのおかたを失望させてしまう…\nそれだけはあってはなりません\nあなた方も、わかっていますわね？", 4, 3, 0.0, 10142, 105, 24, 129901, 105, "2030/12/17 14:59:59", 0.0, 9.08, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "まずまずの結果ではありますが、\nこの程度で満足してもらっては\n困りますわ。エリコ班の一員として、\nより高みを目指していただきますので", 6, 6, 0.0, 10142, 106, 24, 129901, 106, "2030/12/17 14:59:59", 0.0, 0.0, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "私の指導を受けながら、この結果は…\nもっと真剣に考えねばなりませんね\nあなた方が怠けずにいるには、\nどんなしつけが必要かを…クスクス", 3, 8, 0.0, 10142, 107, 24, 129901, 107, "2030/12/17 14:59:59", 0.0, 10.6, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "ひとまず訓練をこなしたご褒美か、\n実力を出しきれたとは言えない罰か…\nみなさんにどちらを与えるべきか\n少し悩む結果ですわね", 6, 4, 0.0, 10142, 108, 24, 129901, 108, "2030/12/17 14:59:59", 0.0, 7.54, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "なかなかいい戦いぶりでしたわ\nこれもあなた方の頑張りと、何より\n優秀な教官である私の教育の賜物\nそうですわね？　クスクスクス…", 2, 7, 0.0, 10142, 109, 24, 129901, 109, "2030/12/17 14:59:59", 0.0, 11.5, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "これだけ進めたのならば合格点ですわ\nでも、もっと高みを目指したいと\n思っているのなら…さらなる訓練にも\n付き合って差し上げましょう", 2, 1, 0.0, 10142, 110, 24, 129901, 110, "2030/12/17 14:59:59", 0.0, 8.83, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "未熟で頼りなかったあなた方が、\n見違えるように成長しました\nなるほど…これこそが、教官冥利に\n尽きるという気持ちなのですね", 1, 2, 0.0, 10142, 111, 24, 129901, 111, "2030/12/17 14:59:59", 0.0, 6.68, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "まさかあなた方が、私の予想すら\n超える力を発揮するとは…驚きました\nもはやゴミ虫などではありません\n一人前の騎士として胸を張りなさい", 6, 2, 0.0, 10142, 112, 24, 129901, 112, "2030/12/17 14:59:59", 0.0, 8.8, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "クスクス、見事な働きです\nみなさんならできると信じていました\n他でもない私の指導を受けた、\nエリコ班の優秀な新兵なのですから", 2, 1, 0.0, 10142, 113, 24, 129901, 113, "2030/12/17 14:59:59", 0.0, 8.9, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", "なんてすばらしい成績…！\n今日という日は『あのおかたを想い\nエリコが限界を超えた記念日』として\n歴史に刻まれることでしょう…！", 2, 5, 0.0, 10142, 114, 24, 129901, 114, "2030/12/17 14:59:59", 0.0, 3.7, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "よし、いい訓練になったな\nおまえたちもよく動けてたし、\nちゃんと成長できてると思うぜ\nその調子で頑張れよっ", 1, 2, 0.0, 10142, 200, 24, 129801, 200, "2030/12/17 14:59:59", 0.0, 7.6, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "ひとまずゴールおめでとう！\nでも、努力は継続してこそだからな\nおまえたちにやる気があるなら、\n何度だって付き合ってやるよ", 2, 1, 0.0, 10142, 201, 24, 129801, 201, "2030/12/17 14:59:59", 0.0, 2.25, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "行軍訓練はこれにて完了！\n…なーんて思ってないよな？\n学んだことが体に染みつくまで\n地道に繰り返すのが練習ってもんさ", 2, 1, 0.0, 10142, 202, 24, 129801, 202, "2030/12/17 14:59:59", 0.0, 3.28, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "みんなに無理をさせちまったか…\nでもこれで諦めることはないぜ\n次はきっとうまくいく。そう信じて\n鍛え続ければ、道は開けるはずだ！", 4, 1, 0.0, 10142, 203, 24, 129801, 203, "2030/12/17 14:59:59", 0.0, 2.98, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "こいつは悔しい結果だな…\nま、反省点はいろいろあったし\nひとつずつ乗り越えていこう\nあたしたちで力を合わせて、なっ！", 4, 1, 0.0, 10142, 204, 24, 129801, 204, "2030/12/17 14:59:59", 0.0, 3.0, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "おまえたちはまだ未熟な訓練兵、\n失敗を必要以上に悔やむことはねえよ\nでも実戦じゃこうはいかないからな\n次は気合を入れ直していけよっ！", 1, 2, 0.0, 10142, 205, 24, 129801, 205, "2030/12/17 14:59:59", 0.0, 10.3, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "これがおまえたちの全力？\nいやいや、そんなはずはないよなっ\nおまえらならもっと強くなれる！\nあたしが言うんだ、間違いないぜ！", 6, 1, 0.0, 10142, 206, 24, 129801, 206, "2030/12/17 14:59:59", 0.0, 2.93, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "おまえたちの実力を考えりゃ、\nベストを尽くせたとは言えない成績だ\nなら、次やるべきことも決まってる\n気持ちを切り替えて、鍛え直すんだ！", 3, 1, 0.0, 10142, 207, 24, 129801, 207, "2030/12/17 14:59:59", 0.0, 9.3, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "まだまだ課題がある内容だったな～\n無駄な動き、判断の遅れ…\nそういうのをしっかり直していけば、\n記録ももっと伸びるはずだっ", 4, 1, 0.0, 10142, 208, 24, 129801, 208, "2030/12/17 14:59:59", 0.0, 6.9, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "ここまでいけりゃ、合格点！\nむしろ、最初の頼りなさを思えば\nすげえ成長してるんじゃねえか？\n胸を張れる結果だと思うぜっ！", 2, 2, 0.0, 10142, 209, 24, 129801, 209, "2030/12/17 14:59:59", 0.0, 0.0, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "なかなかハードな訓練だったけど、\nみんなしっかりついてこられたな\n地道に続けた基礎トレの成果が\n形になってる、その証だぜっ", 1, 2, 0.0, 10142, 210, 24, 129801, 210, "2030/12/17 14:59:59", 0.0, 5.95, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "今回の訓練もよく頑張ったな！\nしっかり休んで次に備えろよ！\nなんつーか、教え子が成長してくのを\n見るのは楽しいもんだな…", 2, 1, 0.0, 10142, 211, 24, 129801, 211, "2030/12/17 14:59:59", 0.0, 6.73, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "おまえら、すげえじゃねえか！\nこれならもう、ひよっこ新兵なんて\n言えねえな。きっと騎士団でも\n大活躍間違いなしだぜ！", 2, 2, 0.0, 10142, 212, 24, 129801, 212, "2030/12/17 14:59:59", 0.0, 0.0, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "敵との戦い方、状況判断の正確さ\n何より根性…どれも最高だったぞ！\nうかうかしてたら、教官のあたしまで\n追い抜かれちまうかもな…へへっ", 1, 2, 0.0, 10142, 213, 24, 129801, 213, "2030/12/17 14:59:59", 0.0, 6.65, "2024/03/31 12:00:00");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", "あたしの指導が良かった？\nいやいや、ここまで強くなれたのは、\n他でもないおまえたち自身が努力した\nおかげだよ。改めて…おめでとうっ！", 6, 1, 0.0, 10142, 214, 24, 129801, 214, "2030/12/17 14:59:59", 0.0, 3.05, "2024/03/31 12:00:00");
